import { describe, expect, it } from '@a0n/gnosis/test';
import { BettyCompiler } from './compiler';
import { lowerLegaleseToGg, segmentLegalese, segmentLegaleseDetailed } from './legalese';

describe('legalese lowering', () => {
  const sampleTerms = `
    Example Terms of Service

    We may change these Terms at any time by posting an updated version of the agreement.
    You must not use the Service to send unlawful content or interfere with other users.
    The service is provided as is and we are not liable for indirect damages.
  `;

  it('segments human legal text into clauses', () => {
    const clauses = segmentLegalese(sampleTerms);

    expect(clauses.length).toBe(3);
    expect(clauses[0]).toContain('change these Terms');
  });

  it('lowers legalese into compiler-valid GG', () => {
    const lowering = lowerLegaleseToGg(sampleTerms, {
      documentId: 'example_terms',
      serviceName: 'Example',
    });
    const parsed = new BettyCompiler().parse(lowering.ggSource);
    const errors = parsed.diagnostics.filter((diagnostic) => diagnostic.severity === 'error');

    expect(errors).toEqual([]);
    expect(parsed.ast?.nodes.has('example_terms')).toBe(true);
    expect(lowering.risks).toContain('unilateral_change');
    expect(lowering.risks).toContain('liability_limit');
    expect(lowering.clauses.some((clause) => clause.kind === 'user_prohibition')).toBe(true);
    expect(lowering.ggSource).toContain('LegalClauseFrame');
    expect(lowering.ggSource).toContain('ACTS_ON');
  });

  it('exposes legalese parsing from BettyCompiler', () => {
    const parsed = new BettyCompiler().parseLegalese(sampleTerms, {
      documentId: 'example_terms',
      serviceName: 'Example',
    });

    expect(parsed.ggSource).toContain('LegalDocument');
    expect(parsed.lowering.summary.clauseCount).toBe(3);
    expect(parsed.ast?.nodes.has('example_terms_summary')).toBe(true);
  });

  it('preserves sections, bullets, and source offsets during segmentation', () => {
    const segmented = segmentLegaleseDetailed(`
      1. Account Rules

      - You must not upload unlawful content.
      - We may suspend your account for breach.
    `);

    expect(segmented.sections[0]?.path).toEqual(['1']);
    expect(segmented.sections[0]?.heading).toBe('Account Rules');
    expect(segmented.clauses).toHaveLength(2);
    expect(segmented.clauses[0]?.sectionPath).toEqual(['1']);
    expect(segmented.clauses[0]?.startOffset).toBeGreaterThanOrEqual(0);
    expect(segmented.clauses[1]?.text).toContain('suspend your account');
  });

  it('extracts definitions and resolves local cross-references', () => {
    const lowering = lowerLegaleseToGg(
      `
        1. Definitions

        "Service" means the hosted application and related features.

        2. Changes

        We may change the Service described in Section 1 by posting notice.
      `,
      { documentId: 'defined_terms', serviceName: 'Defined Terms' }
    );

    const definitionClause = lowering.clauses.find((clause) => clause.definitions.length > 0);
    const changeClause = lowering.clauses.find((clause) => clause.risks.includes('unilateral_change'));

    expect(definitionClause?.definitions[0]?.term).toBe('Service');
    expect(changeClause?.crossReferences[0]?.resolved).toBe(true);
    expect(changeClause?.crossReferences[0]?.resolvedSectionPath).toEqual(['1']);
  });

  it('extracts complete frames and explicit holes for under-supported frames', () => {
    const complete = lowerLegaleseToGg('We may change these Terms by posting notice.', {
      documentId: 'complete_change',
      serviceName: 'Complete Change',
    });
    const ambiguous = lowerLegaleseToGg('These Terms may change from time to time.', {
      documentId: 'ambiguous_change',
      serviceName: 'Ambiguous Change',
    });

    const frame = complete.clauses[0]?.frames.find(
      (entry) => entry.riskKind === 'unilateral_change'
    );
    expect(frame?.actor).toBe('provider');
    expect(frame?.action).toBe('change');
    expect(frame?.object).toBe('terms');
    expect(frame?.conditions).toContain('notice');
    expect(ambiguous.clauses[0]?.holes.map((hole) => hole.kind)).toContain('actor');
  });
});
